import requests
import json
import time
from typing import Dict, List, Optional, Any


class KongAdminAPI:
    def __init__(self, admin_url: str = "http://localhost:8001"):
        self.admin_url = admin_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'Content-Type': 'application/json'})

    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> Dict:
        url = f"{self.admin_url}/{endpoint.lstrip('/')}"
        try:
            if method.upper() == 'GET':
                response = self.session.get(url)
            elif method.upper() == 'POST':
                response = self.session.post(url, json=data)
            elif method.upper() == 'PUT':
                response = self.session.put(url, json=data)
            elif method.upper() == 'PATCH':
                response = self.session.patch(url, json=data)
            elif method.upper() == 'DELETE':
                response = self.session.delete(url)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")
            
            response.raise_for_status()
            return response.json() if response.text else {}
        except requests.exceptions.RequestException as e:
            print(f"Error making request to {url}: {e}")
            if hasattr(e, 'response') and e.response is not None:
                print(f"Response: {e.response.text}")
            raise

    def create_service(self, name: str, url: str, **kwargs) -> Dict:
        data = {
            'name': name,
            'url': url,
            **kwargs
        }
        return self._make_request('POST', '/services', data)

    def get_service(self, service_id: str) -> Dict:
        return self._make_request('GET', f'/services/{service_id}')

    def update_service(self, service_id: str, **kwargs) -> Dict:
        return self._make_request('PATCH', f'/services/{service_id}', kwargs)

    def delete_service(self, service_id: str) -> Dict:
        return self._make_request('DELETE', f'/services/{service_id}')

    def list_services(self) -> List[Dict]:
        response = self._make_request('GET', '/services')
        return response.get('data', [])

    def create_route(self, service_id: str, paths: List[str], **kwargs) -> Dict:
        data = {
            'service': {'id': service_id},
            'paths': paths,
            **kwargs
        }
        return self._make_request('POST', '/routes', data)

    def create_route_by_service_name(self, service_name: str, paths: List[str], **kwargs) -> Dict:
        data = {
            'paths': paths,
            **kwargs
        }
        return self._make_request('POST', f'/services/{service_name}/routes', data)

    def get_route(self, route_id: str) -> Dict:
        return self._make_request('GET', f'/routes/{route_id}')

    def update_route(self, route_id: str, **kwargs) -> Dict:
        return self._make_request('PATCH', f'/routes/{route_id}', kwargs)

    def delete_route(self, route_id: str) -> Dict:
        return self._make_request('DELETE', f'/routes/{route_id}')

    def list_routes(self) -> List[Dict]:
        response = self._make_request('GET', '/routes')
        return response.get('data', [])

    def create_upstream(self, name: str, **kwargs) -> Dict:
        data = {
            'name': name,
            **kwargs
        }
        return self._make_request('POST', '/upstreams', data)

    def get_upstream(self, upstream_id: str) -> Dict:
        return self._make_request('GET', f'/upstreams/{upstream_id}')

    def update_upstream(self, upstream_id: str, **kwargs) -> Dict:
        return self._make_request('PATCH', f'/upstreams/{upstream_id}', kwargs)

    def delete_upstream(self, upstream_id: str) -> Dict:
        return self._make_request('DELETE', f'/upstreams/{upstream_id}')

    def list_upstreams(self) -> List[Dict]:
        response = self._make_request('GET', '/upstreams')
        return response.get('data', [])

    def create_target(self, upstream_id: str, target: str, weight: int = 100, **kwargs) -> Dict:
        data = {
            'target': target,
            'weight': weight,
            **kwargs
        }
        return self._make_request('POST', f'/upstreams/{upstream_id}/targets', data)

    def list_targets(self, upstream_id: str) -> List[Dict]:
        response = self._make_request('GET', f'/upstreams/{upstream_id}/targets')
        return response.get('data', [])

    def delete_target(self, upstream_id: str, target_id: str) -> Dict:
        return self._make_request('DELETE', f'/upstreams/{upstream_id}/targets/{target_id}')

    def add_plugin_to_service(self, service_id: str, plugin_name: str, config: Dict = None) -> Dict:
        data = {
            'name': plugin_name,
        }
        if config:
            data['config'] = config
        return self._make_request('POST', f'/services/{service_id}/plugins', data)

    def add_plugin_to_route(self, route_id: str, plugin_name: str, config: Dict = None) -> Dict:
        data = {
            'name': plugin_name,
        }
        if config:
            data['config'] = config
        return self._make_request('POST', f'/routes/{route_id}/plugins', data)

    def add_global_plugin(self, plugin_name: str, config: Dict = None) -> Dict:
        data = {
            'name': plugin_name,
        }
        if config:
            data['config'] = config
        return self._make_request('POST', '/plugins', data)

    def list_plugins(self) -> List[Dict]:
        response = self._make_request('GET', '/plugins')
        return response.get('data', [])

    def delete_plugin(self, plugin_id: str) -> Dict:
        return self._make_request('DELETE', f'/plugins/{plugin_id}')

    def health_check(self) -> Dict:
        return self._make_request('GET', '/status')


def configure_kong_infrastructure(admin_url: str = "http://localhost:8001"):
    kong = KongAdminAPI(admin_url)
    
    print("Checking Kong health...")
    health = kong.health_check()
    print(f"Kong status: {health}")
    
    print("\n=== Creating Upstream ===")
    upstream = kong.create_upstream(
        name='backend-upstream',
        algorithm='round-robin',
        slots=10000,
        healthchecks={
            'active': {
                'healthy': {
                    'interval': 5,
                    'successes': 2
                },
                'unhealthy': {
                    'interval': 5,
                    'http_failures': 3
                }
            }
        }
    )
    print(f"Created upstream: {upstream['name']} (ID: {upstream['id']})")
    
    print("\n=== Adding Targets to Upstream ===")
    targets = [
        {'target': 'backend1.example.com:8080', 'weight': 100},
        {'target': 'backend2.example.com:8080', 'weight': 100},
        {'target': 'backend3.example.com:8080', 'weight': 50}
    ]
    
    for target_config in targets:
        target = kong.create_target(
            upstream['id'],
            target_config['target'],
            target_config['weight']
        )
        print(f"Added target: {target['target']} (weight: {target['weight']})")
    
    print("\n=== Creating Service with Upstream ===")
    service = kong.create_service(
        name='api-service',
        host='backend-upstream',
        port=80,
        protocol='http',
        path='/api',
        retries=5,
        connect_timeout=60000,
        write_timeout=60000,
        read_timeout=60000
    )
    print(f"Created service: {service['name']} (ID: {service['id']})")
    
    print("\n=== Creating Routes ===")
    route1 = kong.create_route_by_service_name(
        service['name'],
        paths=['/api/v1'],
        methods=['GET', 'POST', 'PUT', 'DELETE'],
        strip_path=False,
        preserve_host=False
    )
    print(f"Created route: {route1['id']} for paths {route1['paths']}")
    
    route2 = kong.create_route_by_service_name(
        service['name'],
        paths=['/api/v2'],
        methods=['GET', 'POST'],
        hosts=['api.example.com']
    )
    print(f"Created route: {route2['id']} for paths {route2['paths']}")
    
    print("\n=== Adding Plugins ===")
    rate_limit_plugin = kong.add_plugin_to_service(
        service['id'],
        'rate-limiting',
        config={
            'minute': 100,
            'hour': 1000,
            'policy': 'local'
        }
    )
    print(f"Added rate-limiting plugin: {rate_limit_plugin['id']}")
    
    cors_plugin = kong.add_plugin_to_service(
        service['id'],
        'cors',
        config={
            'origins': ['*'],
            'methods': ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
            'headers': ['Accept', 'Content-Type', 'Authorization'],
            'exposed_headers': ['X-Auth-Token'],
            'credentials': True,
            'max_age': 3600
        }
    )
    print(f"Added CORS plugin: {cors_plugin['id']}")
    
    print("\n=== Creating Additional Service (Direct URL) ===")
    service2 = kong.create_service(
        name='external-api-service',
        url='https://api.external.com/v1',
        retries=3
    )
    print(f"Created service: {service2['name']} (ID: {service2['id']})")
    
    route3 = kong.create_route_by_service_name(
        service2['name'],
        paths=['/external'],
        strip_path=True
    )
    print(f"Created route: {route3['id']} for external service")
    
    print("\n=== Configuration Summary ===")
    services = kong.list_services()
    print(f"Total services: {len(services)}")
    for svc in services:
        print(f"  - {svc['name']}: {svc.get('host', svc.get('url'))}")
    
    routes = kong.list_routes()
    print(f"\nTotal routes: {len(routes)}")
    for route in routes:
        print(f"  - {route['id']}: {route.get('paths', [])} -> Service ID: {route['service']['id']}")
    
    upstreams = kong.list_upstreams()
    print(f"\nTotal upstreams: {len(upstreams)}")
    for ups in upstreams:
        print(f"  - {ups['name']}")
        targets_list = kong.list_targets(ups['id'])
        for tgt in targets_list:
            print(f"    * {tgt['target']} (weight: {tgt['weight']})")
    
    plugins = kong.list_plugins()
    print(f"\nTotal plugins: {len(plugins)}")
    for plugin in plugins:
        print(f"  - {plugin['name']} on {plugin.get('service', {}).get('id', 'global')}")
    
    return {
        'services': services,
        'routes': routes,
        'upstreams': upstreams,
        'plugins': plugins
    }


if __name__ == '__main__':
    KONG_ADMIN_URL = "http://localhost:8001"
    
    try:
        result = configure_kong_infrastructure(KONG_ADMIN_URL)
        print("\n✓ Kong configuration completed successfully!")
    except Exception as e:
        print(f"\n✗ Error configuring Kong: {e}")
        raise